// Underline the "dm" in the "readme.dm" brand shown in the header title.
// (The blog H1 and the @dm byline are underlined directly in markdown; the
// header title is generated by Material from site_name, so we do it here.)
(function () {
  function underlineDm() {
    document
      .querySelectorAll(".md-header__title .md-ellipsis")
      .forEach(function (el) {
        if (el.querySelector("u")) return; // already done
        if (el.textContent.trim() === "readme.dm") {
          el.innerHTML = el.innerHTML.replace("readme.dm", "readme.<u>dm</u>");
        }
      });
  }

  if (typeof document$ !== "undefined") {
    document$.subscribe(underlineDm); // re-run on Material instant navigation
  } else {
    document.addEventListener("DOMContentLoaded", underlineDm);
    underlineDm();
  }
})();
